/**
 * validation.js — reusable input-validation helpers
 *
 * Each validator returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Validate a numeric id (must be a finite integer > 0).
 * Accepts both number and numeric-string values.
 */
function validateId(value, fieldName = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${fieldName}" is required`);
    return errors;
  }

  const num = Number(value);

  if (!Number.isFinite(num)) {
    errors.push(`"${fieldName}" must be a numeric value`);
    return errors;
  }

  if (!Number.isInteger(num)) {
    errors.push(`"${fieldName}" must be an integer`);
  }

  if (num <= 0) {
    errors.push(`"${fieldName}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name string (must be a non-empty string, 1–100 characters).
 */
function validateName(value, fieldName = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${fieldName}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length < 1) {
    errors.push(`"${fieldName}" must not be empty`);
  }

  if (value.length > 100) {
    errors.push(`"${fieldName}" must be at most 100 characters`);
  }

  return errors;
}

/**
 * Validate an email string (must match RFC-5321-style format, max 254 chars).
 * The regex enforces: local@domain.tld where tld is ≥ 2 alpha characters.
 */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[a-zA-Z]{2,}$/;

function validateEmail(value, fieldName = 'email') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${fieldName}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`"${fieldName}" must be at most 254 characters`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`"${fieldName}" must be a valid email address`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite schema validator
// ---------------------------------------------------------------------------

/**
 * Validate a plain object against a schema definition.
 *
 * Schema shape:
 *   {
 *     id:    { type: 'id',    required: true  },
 *     name:  { type: 'name',  required: true  },
 *     email: { type: 'email', required: true  },
 *   }
 *
 * Returns an array of all error strings collected from every field.
 */
function validateSchema(data, schema) {
  const allErrors = [];

  for (const [field, rules] of Object.entries(schema)) {
    const value = data[field];
    const isAbsent = value === undefined || value === null || value === '';

    // If the field is optional and absent, skip further checks for it.
    if (!rules.required && isAbsent) {
      continue;
    }

    let fieldErrors = [];

    switch (rules.type) {
      case 'id':
        fieldErrors = validateId(value, field);
        break;
      case 'name':
        fieldErrors = validateName(value, field);
        break;
      case 'email':
        fieldErrors = validateEmail(value, field);
        break;
      default:
        // Unknown type — skip silently so callers can extend without breaking.
        break;
    }

    allErrors.push(...fieldErrors);
  }

  return allErrors;
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that validates req.body against the given
 * schema and short-circuits with a 400 response when errors are found.
 *
 * Usage:
 *   app.post('/users', validateBody({ name: { type: 'name', required: true }, ... }), handler);
 */
function validateBody(schema) {
  return (req, res, next) => {
    const errors = validateSchema(req.body || {}, schema);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

/**
 * Returns an Express middleware that validates req.params against the given
 * schema and short-circuits with a 400 response when errors are found.
 *
 * Usage:
 *   app.get('/users/:id', validateParams({ id: { type: 'id', required: true } }), handler);
 */
function validateParams(schema) {
  return (req, res, next) => {
    const errors = validateSchema(req.params || {}, schema);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateSchema,
  validateBody,
  validateParams,
};

