/**
 * Validation helper module.
 * Each validator returns an array of error strings (empty = valid).
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate that required fields are present and non-empty in a body object.
 * @param {object} body
 * @param {string[]} fields
 * @returns {string[]} errors
 */
function validateRequired(body, fields) {
  const errors = [];
  for (const field of fields) {
    if (body[field] === undefined || body[field] === null || body[field] === '') {
      errors.push(`'${field}' is required`);
    }
  }
  return errors;
}

/**
 * Validate that a value is a finite number (or a string that coerces to one).
 * Used for URL params which arrive as strings.
 * @param {string|number} value
 * @param {string} label  Human-readable field name for error messages.
 * @returns {string[]} errors
 */
function validateNumericId(value, label = 'id') {
  const errors = [];
  const n = Number(value);
  if (!Number.isFinite(n) || n !== Math.floor(n) || n <= 0) {
    errors.push(`'${label}' must be a positive integer`);
  }
  return errors;
}

/**
 * Validate that a field is a non-empty string within the allowed length range.
 * @param {*}      value
 * @param {string} label
 * @param {number} minLen
 * @param {number} maxLen
 * @returns {string[]} errors
 */
function validateString(value, label, minLen = 1, maxLen = 255) {
  const errors = [];
  if (typeof value !== 'string') {
    errors.push(`'${label}' must be a string`);
    return errors; // length checks are meaningless without a string
  }
  if (value.length < minLen) {
    errors.push(`'${label}' must be at least ${minLen} character(s) long`);
  }
  if (value.length > maxLen) {
    errors.push(`'${label}' must not exceed ${maxLen} characters`);
  }
  return errors;
}

/**
 * Validate an email address: must be a string, match basic email format,
 * and not exceed 254 characters (RFC 5321 limit).
 * @param {*}      value
 * @param {string} label
 * @returns {string[]} errors
 */
function validateEmail(value, label = 'email') {
  const errors = [];
  if (typeof value !== 'string') {
    errors.push(`'${label}' must be a string`);
    return errors;
  }
  if (value.length > 254) {
    errors.push(`'${label}' must not exceed 254 characters`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`'${label}' must be a valid email address`);
  }
  return errors;
}

/**
 * Convenience: validate the user body fields (name + email).
 * Returns a flat array of all validation errors found.
 * @param {object} body
 * @param {string[]} requiredFields  Which fields to require (default: both)
 * @returns {string[]} errors
 */
function validateUserBody(body, requiredFields = ['name', 'email']) {
  const errors = [];

  errors.push(...validateRequired(body, requiredFields));

  // Only run deeper checks when the field was actually supplied
  if (body.name !== undefined) {
    errors.push(...validateString(body.name, 'name', 1, 100));
  }
  if (body.email !== undefined) {
    errors.push(...validateEmail(body.email, 'email'));
  }

  return errors;
}

/**
 * Express middleware factory: sends a 400 response when `errors` is non-empty.
 * Usage:  const errors = [...]; if (sendIfInvalid(res, errors)) return;
 * @param {object}   res    Express response object
 * @param {string[]} errors
 * @returns {boolean} true when a response was sent (caller should return)
 */
function sendIfInvalid(res, errors) {
  if (errors.length === 0) return false;
  res.status(400).json({ error: 'Validation failed', details: errors });
  return true;
}

module.exports = {
  validateRequired,
  validateNumericId,
  validateString,
  validateEmail,
  validateUserBody,
  sendIfInvalid,
};

