/**
 * validation.js
 * Reusable input-validation helpers for API route handlers.
 *
 * Each exported function returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

'use strict';

// ---------------------------------------------------------------------------
// Low-level field validators
// ---------------------------------------------------------------------------

/**
 * Validates that a value is present (not undefined, null, or empty string).
 * @param {*}      value     - The value to check.
 * @param {string} fieldName - Display name used in error messages.
 * @returns {string|null} An error string, or null if valid.
 */
function validateRequired(value, fieldName) {
  if (value === undefined || value === null || value === '') {
    return `"${fieldName}" is required`;
  }
  return null;
}

/**
 * Validates that a value is a finite number (or a string that parses to one).
 * @param {*}      value     - The value to check.
 * @param {string} fieldName - Display name used in error messages.
 * @returns {string|null} An error string, or null if valid.
 */
function validateNumeric(value, fieldName) {
  if (value === undefined || value === null) return null; // let validateRequired handle absence
  const num = Number(value);
  if (!Number.isFinite(num)) {
    return `"${fieldName}" must be a numeric value`;
  }
  return null;
}

/**
 * Validates that a value is a non-empty string.
 * @param {*}      value     - The value to check.
 * @param {string} fieldName - Display name used in error messages.
 * @returns {string|null} An error string, or null if valid.
 */
function validateString(value, fieldName) {
  if (value === undefined || value === null) return null; // let validateRequired handle absence
  if (typeof value !== 'string') {
    return `"${fieldName}" must be a string`;
  }
  return null;
}

/**
 * Validates the minimum and/or maximum length of a string value.
 * Assumes the value has already passed validateString().
 *
 * @param {*}           value     - The value to check.
 * @param {string}      fieldName - Display name used in error messages.
 * @param {{ min?: number, max?: number }} options
 * @returns {string|null} An error string, or null if valid.
 */
function validateStringLength(value, fieldName, { min, max } = {}) {
  if (typeof value !== 'string') return null; // type error already reported elsewhere
  if (min !== undefined && value.length < min) {
    return `"${fieldName}" must be at least ${min} character${min === 1 ? '' : 's'} long`;
  }
  if (max !== undefined && value.length > max) {
    return `"${fieldName}" must be no more than ${max} characters long`;
  }
  return null;
}

/**
 * Validates that a string value matches a valid e-mail address format.
 * Uses a RFC-5321-inspired pattern that covers the vast majority of real
 * addresses while rejecting clearly malformed input.
 *
 * @param {*}      value     - The value to check.
 * @param {string} fieldName - Display name used in error messages.
 * @returns {string|null} An error string, or null if valid.
 */
function validateEmail(value, fieldName) {
  if (typeof value !== 'string') return null; // type error already reported elsewhere
  // local-part @ domain  (domain must contain at least one dot)
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return `"${fieldName}" must be a valid email address`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Composite validators for common field groups
// ---------------------------------------------------------------------------

/**
 * Runs all applicable validations for a `name` field and returns the list of
 * error messages (empty array = valid).
 *
 * Rules: required, must be a string, 1–100 characters.
 *
 * @param {*}      value   - Raw value from the request body / params.
 * @param {boolean} required - Whether the field must be present.
 * @returns {string[]}
 */
function validateNameField(value, required = true) {
  const errors = [];
  const collect = (err) => { if (err) errors.push(err); };

  if (required) collect(validateRequired(value, 'name'));
  collect(validateString(value, 'name'));
  collect(validateStringLength(value, 'name', { min: 1, max: 100 }));

  return errors;
}

/**
 * Runs all applicable validations for an `email` field and returns the list
 * of error messages (empty array = valid).
 *
 * Rules: required, must be a string, max 254 characters, valid e-mail format.
 *
 * @param {*}      value    - Raw value from the request body / params.
 * @param {boolean} required - Whether the field must be present.
 * @returns {string[]}
 */
function validateEmailField(value, required = true) {
  const errors = [];
  const collect = (err) => { if (err) errors.push(err); };

  if (required) collect(validateRequired(value, 'email'));
  collect(validateString(value, 'email'));
  collect(validateStringLength(value, 'email', { max: 254 }));
  collect(validateEmail(value, 'email'));

  return errors;
}

/**
 * Runs all applicable validations for a route-parameter `id` and returns the
 * list of error messages (empty array = valid).
 *
 * Rules: required, must be numeric.
 *
 * @param {*} value - Raw value (typically a string from req.params).
 * @returns {string[]}
 */
function validateIdParam(value) {
  const errors = [];
  const collect = (err) => { if (err) errors.push(err); };

  collect(validateRequired(value, 'id'));
  collect(validateNumeric(value, 'id'));

  return errors;
}

// ---------------------------------------------------------------------------
// Request-level validators (combine field validators for a full endpoint)
// ---------------------------------------------------------------------------

/**
 * Validates the body of a POST /users request.
 * Both `name` and `email` are required.
 *
 * @param {object} body - req.body
 * @returns {string[]} Flat list of validation errors.
 */
function validateCreateUser(body = {}) {
  return [
    ...validateNameField(body.name, true),
    ...validateEmailField(body.email, true),
  ];
}

/**
 * Validates the body of a PUT /users/:id request.
 * At least one of `name` or `email` must be supplied; whichever fields are
 * present are validated according to their individual rules.
 *
 * @param {object} body - req.body
 * @returns {string[]} Flat list of validation errors.
 */
function validateUpdateUser(body = {}) {
  const errors = [];

  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('At least one of "name" or "email" must be provided');
    return errors;
  }

  if (hasName)  errors.push(...validateNameField(body.name,   true));
  if (hasEmail) errors.push(...validateEmailField(body.email, true));

  return errors;
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that validates req.params.id and calls next()
 * when valid, or responds with 400 + descriptive errors when invalid.
 */
function requireNumericId() {
  return (req, res, next) => {
    const errors = validateIdParam(req.params.id);
    if (errors.length) {
      return res.status(400).json({ errors });
    }
    // Coerce to number so downstream handlers can use it directly
    req.params.id = Number(req.params.id);
    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Low-level
  validateRequired,
  validateNumeric,
  validateString,
  validateStringLength,
  validateEmail,

  // Field-level
  validateNameField,
  validateEmailField,
  validateIdParam,

  // Request-level
  validateCreateUser,
  validateUpdateUser,

  // Middleware
  requireNumericId,
};

'use strict';

// Simple application with comprehensive input validation on all API endpoints.

const express = require('express');
const {
  requireNumericId,
  validateCreateUser,
  validateUpdateUser,
} = require('./validation');

const app = express();

// ---------------------------------------------------------------------------
// Middleware
// ---------------------------------------------------------------------------

// Parse JSON request bodies; respond with 400 on malformed JSON.
app.use(express.json());
app.use((err, req, res, next) => {
  if (err.type === 'entity.parse.failed') {
    return res.status(400).json({ errors: ['Request body contains invalid JSON'] });
  }
  next(err);
});

// ---------------------------------------------------------------------------
// In-memory data store (stand-in for a real database)
// ---------------------------------------------------------------------------

let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob',   email: 'bob@example.com'   },
];
let nextId = 3;

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

/** GET /health — liveness check (no user input to validate) */
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

/**
 * GET /users — list all users.
 * No input validation needed; query-string params are ignored.
 */
app.get('/users', (req, res) => {
  res.json(users);
});

/**
 * GET /users/:id — fetch a single user by id.
 *
 * Validations:
 *   - id must be present
 *   - id must be numeric
 */
app.get('/users/:id', requireNumericId(), (req, res) => {
  const user = users.find((u) => u.id === req.params.id);
  if (!user) {
    return res.status(404).json({ errors: [`No user found with id ${req.params.id}`] });
  }
  res.json(user);
});

/**
 * POST /users — create a new user.
 *
 * Validations:
 *   - name: required, string, 1–100 chars
 *   - email: required, string, max 254 chars, valid email format
 */
app.post('/users', (req, res) => {
  const errors = validateCreateUser(req.body);
  if (errors.length) {
    return res.status(400).json({ errors });
  }

  const { name, email } = req.body;
  const newUser = { id: nextId++, name, email };
  users.push(newUser);

  res.status(201).json(newUser);
});

/**
 * PUT /users/:id — replace (update) an existing user's fields.
 *
 * Validations:
 *   - id must be present and numeric (via requireNumericId middleware)
 *   - At least one of name or email must be supplied
 *   - name (if provided): string, 1–100 chars
