// validation.js — reusable field-validation helpers

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user id parameter (must be a positive integer).
 * @param {*} value  - raw value (typically a route param string)
 * @returns {string|null} error message, or null if valid
 */
function validateId(value) {
  const n = Number(value);
  if (!Number.isInteger(n) || n <= 0) {
    return `id must be a positive integer, got: "${value}"`;
  }
  return null;
}

/**
 * Validate a name field.
 * @param {*} value
 * @returns {string|null}
 */
function validateName(value) {
  if (typeof value !== 'string') {
    return `name must be a string, got: ${typeof value}`;
  }
  const trimmed = value.trim();
  if (trimmed.length < 1) {
    return 'name must be at least 1 character';
  }
  if (trimmed.length > 100) {
    return `name must be at most 100 characters, got: ${trimmed.length}`;
  }
  return null;
}

/**
 * Validate an email field.
 * @param {*} value
 * @returns {string|null}
 */
function validateEmail(value) {
  if (typeof value !== 'string') {
    return `email must be a string, got: ${typeof value}`;
  }
  if (value.length > 254) {
    return `email must be at most 254 characters, got: ${value.length}`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `email must be a valid email address, got: "${value}"`;
  }
  return null;
}

/**
 * Assert that every key in `requiredFields` is present (non-undefined) in `body`.
 * @param {object} body
 * @param {string[]} requiredFields
 * @returns {string[]} list of error messages (empty if all present)
 */
function validateRequired(body, requiredFields) {
  return requiredFields
    .filter((field) => body[field] === undefined || body[field] === null)
    .map((field) => `${field} is required`);
}

/**
 * Run a map of { fieldName: validatorFn } over `data`, collecting errors.
 * Only runs a validator when the field is actually present in `data`.
 *
 * @param {object} data        - object to validate (req.body or req.params)
 * @param {object} validators  - { fieldName: (value) => string|null }
 * @returns {string[]} collected error messages
 */
function runValidators(data, validators) {
  const errors = [];
  for (const [field, validate] of Object.entries(validators)) {
    if (data[field] !== undefined && data[field] !== null) {
      const error = validate(data[field]);
      if (error) errors.push(error);
    }
  }
  return errors;
}

/**
 * Convenience: collect required-field errors AND type/format errors.
 * Returns a combined, deduplicated array.
 *
 * @param {object} data
 * @param {string[]} requiredFields
 * @param {object} validators
 * @returns {string[]}
 */
function validate(data, requiredFields, validators) {
  const missing = validateRequired(data, requiredFields);
  // Only run type/format validators for fields that ARE present.
  const invalid = runValidators(data, validators);
  return [...missing, ...invalid];
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateRequired,
  runValidators,
  validate,
};

