// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Validate a numeric id (route parameter or body field).
 * Accepts numbers and numeric strings; rejects anything else.
 */
function validateId(value, fieldName = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${fieldName}" is required`);
    return errors;
  }

  const num = Number(value);
  if (!Number.isFinite(num) || Number.isNaN(num)) {
    errors.push(`"${fieldName}" must be a numeric value`);
  } else if (!Number.isInteger(num)) {
    errors.push(`"${fieldName}" must be an integer`);
  } else if (num <= 0) {
    errors.push(`"${fieldName}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name string (1–100 characters).
 */
function validateName(value, required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push('"name" is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('"name" must be a string');
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length === 0) {
    errors.push('"name" must not be blank');
  } else if (trimmed.length > 100) {
    errors.push(`"name" must be at most 100 characters (received ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an email address (string, valid format, max 254 characters).
 * Uses a broadly accepted RFC-5321-aligned regex.
 */
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function validateEmail(value, required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push('"email" is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('"email" must be a string');
    return errors;
  }

  if (value.length > 254) {
    errors.push(`"email" must be at most 254 characters (received ${value.length})`);
  }

  if (!EMAIL_RE.test(value)) {
    errors.push('"email" must be a valid email address');
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators for specific request shapes
// ---------------------------------------------------------------------------

/**
 * Validate the body of a POST /users request.
 * Both "name" and "email" are required.
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];
}

/**
 * Validate the body of a PUT /users/:id request.
 * At least one of "name" or "email" must be present;
 * whichever fields are present are fully validated.
 */
function validateUpdateUser(body) {
  const errors = [];
  const hasName = body.name !== undefined && body.name !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('Request body must include at least one of "name" or "email"');
    return errors;
  }

  if (hasName) errors.push(...validateName(body.name, false));
  if (hasEmail) errors.push(...validateEmail(body.email, false));

  return errors;
}

/**
 * Validate a numeric route parameter (e.g. :id).
 */
function validateRouteId(params, fieldName = 'id') {
  return validateId(params[fieldName], fieldName);
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that runs `validatorFn` against the
 * appropriate part of the request and short-circuits with a 400 response
 * when errors are found.
 *
 * @param {Function} validatorFn  - (req) => string[]
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({ error: 'Validation failed', details: errors });
    }
    next();
  };
}

