'use strict';

// Simple application for agent to work on

const express = require('express');
const {
  validate,
  validateCreateUser,
  validateUpdateUser,
  validateRouteId,
} = require('./validation');

const app = express();
app.use(express.json());

// ---------------------------------------------------------------------------
// In-memory store (replace with a real DB layer as needed)
// ---------------------------------------------------------------------------
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob',   email: 'bob@example.com'   },
];
let nextId = 3;

// ---------------------------------------------------------------------------
// GET /health — no input to validate
// ---------------------------------------------------------------------------
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ---------------------------------------------------------------------------
// GET /users — returns all users (no input validation needed)
// ---------------------------------------------------------------------------
app.get('/users', (req, res) => {
  res.json(users);
});

// ---------------------------------------------------------------------------
// GET /users/:id
//   Validates: id is a positive integer
// ---------------------------------------------------------------------------
app.get(
  '/users/:id',
  validate((req) => validateRouteId(req.params, 'id')),
  (req, res) => {
    const id = Number(req.params.id);
    const user = users.find((u) => u.id === id);
    if (!user) {
      return res.status(404).json({ error: `User with id ${id} not found` });
    }
    res.json(user);
  },
);

// ---------------------------------------------------------------------------
// POST /users
//   Validates: name (required, string, 1-100 chars)
//              email (required, string, valid format, max 254 chars)
// ---------------------------------------------------------------------------
app.post(
  '/users',
  validate((req) => validateCreateUser(req.body)),
  (req, res) => {
    const { name, email } = req.body;
    const user = { id: nextId++, name: name.trim(), email };
    users.push(user);
    res.status(201).json(user);
  },
);

// ---------------------------------------------------------------------------
// PUT /users/:id
//   Validates: id is a positive integer (route param)
//              at least one of name / email present in body
//              name (string, 1-100 chars) when provided
//              email (string, valid format, max 254 chars) when provided
// ---------------------------------------------------------------------------
app.put(
  '/users/:id',
  validate((req) => [
    ...validateRouteId(req.params, 'id'),
    ...validateUpdateUser(req.body),
  ]),
  (req, res) => {
    const id = Number(req.params.id);
    const user = users.find((u) => u.id === id);
    if (!user) {
      return res.status(404).json({ error: `User with id ${id} not found` });
    }

    if (req.body.name !== undefined) user.name = req.body.name.trim();
    if (req.body.email !== undefined) user.email = req.body.email;

    res.json(user);
  },
);

// ---------------------------------------------------------------------------
// DELETE /users/:id
//   Validates: id is a positive integer
// ---------------------------------------------------------------------------
app.delete(
  '/users/:id',
  validate((req) => validateRouteId(req.params, 'id')),
  (req, res) => {
    const id = Number(req.params.id);
    const index = users.findIndex((u) => u.id === id);
    if (index === -1) {
      return res.status(404).json({ error: `User with id ${id} not found` });
    }

    const [deleted] = users.splice(index, 1);
    res.json({ message: `User ${id} deleted`, user: deleted });
  },
);

// ---------------------------------------------------------------------------
// Start server (skipped when required as a module, e.g. in tests)
// ---------------------------------------------------------------------------
if (require.main === module) {
  app.listen(3000, () => {
    console.log('Server running on port 3000');
  });
}

module.exports = app;
